output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?seriesLabel ?games WHERE {
  VALUES ?seriesLabel {
    "1975 American League Championship Series" "2013 American League Championship Series" "2018 World Series"
  }
  ?series rdfs:label ?seriesLabel .
  FILTER(LANG(?seriesLabel) = "en")
  ?series wdt:P1350 ?games .
  FILTER(BOUND(?games))
}

